import{_ as e,c as a,ap as t,o as _}from"./chunks/framework.CCxIPCIe.js";const h=JSON.parse('{"title":"北大哲学系 2025 年开学典礼和毕业典礼上的演讲","description":"","frontmatter":{"title":"北大哲学系 2025 年开学典礼和毕业典礼上的演讲","date":"2026-05-21T20:53:01.132Z","length":"5288字","time":"18分钟","aside":false,"hash":341820671},"headers":[],"relativePath":"excerpt/北大2025年哲学系开学典礼和毕业典礼上的演讲.md","filePath":"excerpt/北大2025年哲学系开学典礼和毕业典礼上的演讲.md"}'),r={name:"excerpt/北大2025年哲学系开学典礼和毕业典礼上的演讲.md"};function o(s,p,c,i,l,n){return _(),a("div",null,p[0]||(p[0]=[t('<p>作者：程乐松 北京大学哲学系与宗教学系主任</p><div class="info custom-block"><p class="custom-block-title">按</p><p>在 B 站上看到程乐松老师的采访，他对景观化与身体性的观点与我感悟相合，遂找来其开学典礼和毕业典礼的演讲稿来看，相见恨晚，所见略同。</p></div><h2 id="开学典礼演讲" tabindex="-1">开学典礼演讲 <a class="header-anchor" href="#开学典礼演讲" aria-label="Permalink to &quot;开学典礼演讲&quot;">​</a></h2><p>各位同事，各位同学：</p><p>大家下午好！</p><p>其实我们绝大部分的生活看起来很有秩序和意义的原因有以下两个：周期性和仪式感。之所以要用仪式感的方式来标定独特的周期，是为了让人在完善的预期和稳定的情绪中完成角色的转换。同时，周期性则保证了在某个特定生活世界中的人保持一种可感的新鲜感。对于大学的教员和学生而言，开学典礼就是这样兼具周期性和仪式感的场合。一般而言，哲学系开学典礼的标准程式是介绍我们的学术传统和影响力、学科领导力，同时给各位同学一些关于读书和思考的提示与建议——这些提示和建议往往都是以鼓励为主的。</p><p>我想我们这个学术共同体最不需要塑造和巩固的共识就是北大哲学门的悠久学术传统、独特研究风格和雄厚学科实力。况且，读书和思考是一个高度个体化的事情，无需刻板的统一。哲学的价值在于用规范化知识的严格传递和高度开放的思想实践之间的平衡保护每个个体的思想风格和精神态度。此外，哲学的丰富内容也保证每一个尝试接近哲学的人都可以在如此风格迥异的知识体系和思想世界中找到精神相契的心头之好。哲学虽然是一个高度规范性的学科，同时却是一个天然拒斥标准化的精神生活方式。那种流水线式的标准化知识生产和复制，让我们成为哲学家的复读机，让同学们成为现代学术工业的标准产品，是对哲学最致命的背叛。不妨说，北大哲学门是从规范走向个性，以体系化的知识为基础塑造反思的习惯。</p><p>因此，在我看来，与其给大家一大堆的学术和学习建议，形成一个空洞且并无多大价值的“共识”，还不如与大家说一些学术以外的生活经验。</p><p>就我自己而言，生活的根本任务在于，找到属于你的、适当且愉快的生活方式。具体到大学校园里的生活方式，我无法断定心无旁骛的读书写作与心猿意马的上蹿下跳到底哪个更好，因为那是你们自己的感受和决定，而且最终的结果是你们来承担。作为一个老师，如果希望自己的学生无一例外地都是天生的书虫，那在我看来是一种懒惰和不自信的表现；当然，如果希望自己的学生都无所用心地成为标准知识接收器，又是不负责任且对哲学这一学科不尊重的表现。我可以将何谓适当且愉快这一问题留给每一个在座的同学。</p><p>我自己的经验是，在我们这个时代读哲学最大的挑战不是来自学科的知识难度和持续学习的耐心，而是无处不在的质疑，特别是基于工具理性和实用主义的、那种自以为是的精明带来的无知的傲慢。学习哲学的我们，需要在生活中封闭、在思想中开放。活得纯粹一些，想得复杂一点；选书的时候三心二意，读书的时候耐心专注。大学有时候比社会还要令人眼花缭乱，其原因就是这里，很多行为方式是高度理想主义的，而且对后果懵懂无知、无所畏惧，这样的丰富和多元对于仍处于自我理解成型期的你们而言是难以驾驭的。将自己的注意力放在这些纷乱且看起来十分多元的选择之中，且去逐一尝试，是比较笨拙且缺乏策略的。持续的尝试和不断地变化，不敢做选择，从心灵状态上看，无非是不自信在生活中表现出来的典型症状而已。因此，我给各位的建议是，即使没有专注读书，也不要像一个花蝴蝶一样出现在校园活动和社交的每一个场合，太多的选项与没有选项在本质上是一样的。我将这种“物理性参与 精神性游离”定义为“校园生活的渣男状态”。你自以为自己是生活的主导者，实际上，你可能只是因为不自信和恐惧在拙劣模仿、盲目跟随。没有发自内心的肯认，我们在任何热闹中都是局外人。</p><p>如果你发现你的大学生活出现以下两种情况，你就需要高度警惕并进行严格反思：其一就每天忙得不可开交，细想起来，每件事情做起来并没有多少真正发自内心的愉悦，而且连留给自己发呆和自由阅读的时间都成为奢侈；其二进入了惯性的拖延，大部分的时间和情绪都消耗在最优选择的陷阱里，且在认真做事之前就想好了失败的退路。这两种情况看起来完全不同，但其内在机制是一样的，就是缺乏清晰的自我认识，且无法找到专注投身的状态和目标。这可以被简单地定义为缺乏深刻感受力和果敢决断力的症状，不能形成自信的笃定。我认为，如果学习哲学可以让一个人得到自信的笃定和笃定的自信，就是极为成功的。</p><p>与此相对的，如果你的确不知道你自己想要或者适合什么，大可不必焦虑和着急。真正可怕的，不是自我认知形成的缓慢，而是在这一过程里迷失在缺乏稳定自我理解的焦虑和恐惧情绪之中。三十年前我进入北京大学哲学系学习，我一直不知道自己要干什么，适合干什么。很坦率的说，我是一直到进入大学之后的十六年，成为老师的第六年，我才完全确立职业学者和哲学教师的自我认同。实际上，相对于不断涌向我们的无限丰富的不确定性，任何高瞻远瞩的人生规划，和十分精密的算计在时间面前不仅是脆弱的，甚至是可笑和荒谬的。</p><p>卓别林说，长镜头下的人生是喜剧，以特写方式观察细节都是悲剧。究其原因，当下的精明算计与未来的人生回顾是两个完全不同的思想维度。我可以负责任地说，当下所有的精明算计从人生的跨度出发都显得笨拙和短视。因为精明实际上就是功利与急躁的代名词，其前提放弃自主思考和选择的权利，以流俗和从众的方式定义自我的价值，逃避面对自己的责任，最终牺牲的是稳定的自我认同。看似精明的算计，不仅会造成持续的浮躁和急切，还会因为沉溺于想象出来的远大前程而消磨当下的专注和热情。与其想着自己要成为一个伟大的哲学家，不如想想今天准备看几页书，明天打算去怎么锻炼…精明算计出来的远大前程和镜花水月一样，毫无价值——无论从现实利益出发，还是从心灵平静来看都是如此。我希望大家不要用精明的利益算计来代替深入内心的反思，也不要用虚无缥缈的伟大前程来消磨投入当下的热情。</p><p>我自己的另一个重要经验就是，大学或研究生的生涯是各位一生中最宝贵的、塑造自我的机会：你已经有了一定的认知和思考能力，不断接触人类历史上那些最伟大的心灵，且在充满可能性且鼓励尝试的理想主义校园里以试错的方式发现自我的边界。结合我们的学科特点，各位的校园生涯是否有价值可以参照如下三个标准：其一，以有独到心得的哲学知识为基础形成的自我理解，将持续的探索和反思作为一种生活方式确立下来，保持好奇心的同时避免出现知识的傲慢；其二，如果不能清晰地确立笃定的自我理解，那么至少明确自己不适合或者不喜欢什么，且不会因此陷入自我怀疑和否定；其三，形成一种稳定且克制的行为习惯和生活方式，并且能够在一定程度上抵御来自外部世界的喧闹和质疑。</p><p>当然，还有一个很哲学的建议：如果你们不能同意，在未来无法落实上述建议，千万别有任何意义上的自我否定和怀疑，因为我们不需要毫无质疑地接受任何人的任何建议。如果可以在保持当下的心灵平静，且在未来不反复懊恼和悔恨，那么任何一段时光都是值得的。陷入焦虑和懊恼且无法自拔，是我能够想象的、唯一浪费生命的方式。</p><p>哲学是心灵的事业，而且最终面对的是自己的心灵世界。如果可能，就一起尝试活得哲学一些，涵养出直面内心的勇气和能力，我想这才是对哲学门最有价值的回应！</p><p>祝大家开学愉快，谢谢大家！</p><h2 id="毕业典礼演讲" tabindex="-1">毕业典礼演讲 <a class="header-anchor" href="#毕业典礼演讲" aria-label="Permalink to &quot;毕业典礼演讲&quot;">​</a></h2><p>尊敬的张尊超先生、刘黄女士、刘凯系友、韩水法老师，以及各位在座的老师、同学们，还有各位家长朋友们：</p><p>大家上午好！</p><p>首先，我要祝贺在座的各位毕业生，在并不算漫长的智性试炼和知识学习之后——无论这一过程是愉快还是不甚顺遂的，你们都取得了阶段性的成果，迎来了一次重要的人生转场。你们即将面对的是更大的世界，虽然那未必是令人愉悦的，但大抵是值得期待的。喜悦总是在告别一种单调且艰难的生活、迎来未知的可能性的独特时刻涌现出来的。于我而言，在一个祝福冗余的时刻，溢美的鼓励是最无关紧要的。换言之，态度可能要比内容重要，我将以下的内容视作态度的表达，而非任何意义上的说教。</p><p>师生之间以离别之名送上祝福和感谢，以掩盖过往数年间煎熬的无奈和苦楚。此后，我们就依赖时间和空间的距离将师生之间的交往和大学生活都修饰成为充满亮色的温馨记忆。不妨说，与祝福伴生的，是选择性遗忘的序曲，而与叮咛共在的，则是对抗这种遗忘的手段。</p><p>作为一个教师，我不愿意让各位沉浸在逃离和遗忘的窃喜之中，要以反思的方式为盲目的情绪提供冷却剂。在被祝福的热情和憧憬的喜悦淹没的时刻，更需要以冷静且自觉的方式展现哲学在心灵上留下的印记。我们的确未必能够——或者说肯定不可能——透彻地洞悉世界，但始终朝向困扰我们的难题展开反思应该成为作为生活方式的哲学的样貌。</p><p>我们所处的时代，技术的狂欢让器物变得日益丰盈，与之相对的则是精神世界的日渐贫乏。我们沉溺于屏幕里的喧嚣，遮掩着内心的空洞。宁愿在虚拟世界中游荡，也不愿意投身于现实的生活。用事不关己的信息浪潮来填充时间，不愿意处理眼前的事务。我们与生活之间，产生了一种独特的疏离感，要么感觉身体在此处，心灵在别处；要么感觉自己是生活的局外人。无孔不入的竞争让我们的身体在忙碌中被占据了，我们的心灵则被焦虑攫取。时间的物理化带走了生命的温度和感受的丰富。如果世界是一个叫做活着的剧场，那么绝大多数的人都不愿意或并没有真实地投身其中。在投身于生活之前，就已经深陷想象出来的困顿和失意之中了：在关于生活的琐碎、失败的焦虑，以及无意义的自我否定之中踯躅不前。不妨说，我们冗余的想象力正在吞噬着生活的意义与勇气。</p><p>在无死角、不停歇的竞争，以及结果导向的个体价值评判构成的整体暴力之下，我们似乎注定是被弱肉强食的游戏抛出局的“分母”。可怕的是，在这一被想象出来的结果真正到来之前，它就在持续地折磨和消耗着我们；在我看来，这一想象性的结果实际上是自我迷失与丛林法则的共谋，因为这个竞争游戏的标准和目标不是来自内心的热爱，而是彻底空洞和抽象的。其后果就是，在持续的挫败感和心底不甘平庸的摇摆中，生活的意义都被掏空了。由此，生活陷入自我价值否定的“死亡螺旋”之中：间歇性努力，持续性懒散；战略性勤奋，战术性拖延；意愿性进取，行动性摆烂。日常生活都像是憋着一口气的冲刺，在无氧运动的心肺极限里度过漫长的日常，这种状态不仅让人身心俱疲，更难以为继。</p><p>描述这些典型的集体症状，并不是要与大家一起抱怨生活，而是尝试做一些分析。在我看来，在人生各个阶段大家得到或看到的祝福或鼓励，都陷入了表达上的谬误。这些谬误可以定义为“空洞的形容词性”以及“抽象的功利主义”。诸如坚定做自己、永不言弃之类的话语，其表达重点都在语词的状态描述。至于何谓自己、奋斗的目标，不放弃的理由等关键内容，都是付之阙如的。此外，“人生从来没有太晚的开始，只有太早的放弃”之类的描述，似乎陷入了“无对象”的怪圈，要开始或放弃什么？这个“什么”为什么值得开始或者能够放弃？抽象的功利主义用目标的抽象和路径的缺乏剥夺了过程的意义。我们感受到的不是脚踏实地的安然、投身日常的平静和稳步前行的欣喜，而是现实的具体及琐碎与“空洞且抽象的功利目标”之间的巨大鸿沟，其后果就是焦躁、无力与绝望。当所有目的都变成手段，我们就进入了无目的的迷茫，最终我们丧失的，不仅是做事的耐心与勇气，还有真实生活的感知力。具体的努力与抽象的价值之间有无限远的距离，这带来的是不断冲刺的压力和持续的自我怀疑。当下行动的意义缺失和相对于抽象功利主义目标的持续挫败感又会让我们失去发自内心地热爱的能力。</p><p>为生活重建具体而微的行动价值是应对上述困境的办法。投身任何行动之前，先审视一下目标；否定自己之前，先分析一下现状。一个非常重要，甚至可以说是最为重要的能力，就是区分理想与欲望。欲望是缺乏的症状，特别是社会竞争中出现的胜负欲、成就欲，大抵是你落入优绩主义彀中的标志。与之相对，理想是一种自我期许，它带来的是一种内生的动力和内心的平和，能够帮你去屏蔽那些外在评判带来的心理负担。你是谁，你看起来像谁，你希望你自己看起来像谁，这是三个不同层次的问题，不能混淆。</p><p>另一个显而易见的事实是，成功与否是一种外在判断，而平和的快乐却是一种难以自欺的直接感受。因此，不要用别人眼中的好取代甚至杀死你的平静。由此，我们要仔细地检视自己的幸福列表，哪些是被别人的眼中的好塑造出来的，哪些是因为要逃避生活的真实而被你臆造出来的。当然，也不能认为，别人眼中的好都是幸福的天敌，任何武断的全称判断都应该引起哲学的警惕。</p><p>此外，生活的最大天敌就是不自觉地陷入虚假的表演——不是做自己，而是在表演别人眼中的自己。我们需要对具有表演性的积极状态保持高度的警惕。我想用为己之学来说明真实生活与虚假表演之间的区别，“为己之学”的目标不是为了赢得竞争优势而获得知识壁垒，也不是为了塑造别人眼中的自我来掩盖内心的不坚定，而是自觉投身当下，知晓并肯认其价值。进而言之，与其追求被人仰望的、抽象的伟大，不如平和地专注当下的行动。在我看来，所有被人仰望的都是平和自觉及专注投身的副产品。</p><p>生命是生死之间的摆渡，哲学是这一旅途中的渡船，她让我们谨慎地在盲目的信念与极端的怀疑之间取得平衡。理性不是谋杀感受与快乐的凶器，而是它们的守护者。生命是一个充满未知的过程，不要恐惧，迎接它；不要设计，感受它。同时，痛苦与挫折是我们的心灵赋予我们的、感受外部世界，持续塑造自我的独特能力，它们是生活的常态，让我们学会从追求盲目的快乐转变为与理性的平和共处。哲学的价值在于我们无需亲身经历所有苦难和谬误，就可以探寻自我的真相，并投身具体的生活。灵魂的高贵是隐忍的安然与投身的自觉，静水流深才是生命的理想形态。对待自己的生命，我们大可以大胆和勇敢一些，毕竟它是在无限敞开中必然戛然而止的一次单向旅程。</p><p>哲学被时代定义成为“无用之学”，是因为哲学作为“为己之学”的精神试炼与职业分科之学需要的“刚性知识”壁垒之间存在着根本冲突。哲学不会直接产生可计价的交换价值，因为她始终专注以平和的自觉为目标的、对时代与世界的审慎观察，而不是成为可与他人交换的“产品”。我们所理解的“可交换价值”都是自我塑造的次生“产品”。从这个意义上说，以反思达成理解，是每一个人都必须拥有作为方法的哲学的根本原因。</p><p>如何成为一个合格的哲学人，是一道直抵内心的终生考题。我们要用生活实践和心灵状态去证明，没有辜负哲学这一为己之学的真正价值！以此与诸君共勉。</p><p>谢谢大家！</p>',33)]))}const m=e(r,[["render",o]]);export{h as __pageData,m as default};
